import React from 'react';
import { MoreVertical } from 'lucide-react';

const KnowledgeCard = ({ knowledge, onClick }) => {
  return (
    <div 
      onClick={onClick}
      className="bg-white rounded-xl border border-border-gray p-6 hover:shadow-lg transition-all duration-300 cursor-pointer group animate-fade-in"
    >
      {/* Top right - Three dots icon always visible */}
      <div className="flex justify-end mb-2">
        <button 
          className="p-1 hover:bg-gray-100 rounded-lg transition-colors"
          onClick={(e) => e.stopPropagation()}
        >
          <MoreVertical size={18} className="text-gray-400 hover:text-gray-600" />
        </button>
      </div>
      
      <h3 className="text-lg font-semibold text-secondary mb-2 -mt-1">{knowledge.name}</h3>
      <p className="text-gray-600 text-sm line-clamp-2 mb-4">{knowledge.description}</p>
      
      <div className="text-xs text-gray-400">
        Created On: {knowledge.createdOn}
      </div>
    </div>
  );
};

export default KnowledgeCard;
